341	// checkVersionGate blocks execution if the binary is older than the project requires.
342	// Returns an error for non-exempt commands when binary version < project's ddx_version.
343	func (f *CommandFactory) checkVersionGate(cmd *cobra.Command) error {
344		// Dev builds bypass the gate
345		if f.Version == "" || f.Version == "dev" {
346			return nil
347		}
348	
349		// Read project versions
350		projectVersion := readProjectVersions(f.WorkingDir)
351		if projectVersion == "" || projectVersion == "dev" {
352			return nil // No versions.yaml or dev project — skip
353		}
354	
355		// Exempt commands that must work even when binary is too old
356		switch cmd.Name() {
357		case "upgrade", "version", "doctor", "init", "help", "completion":
358			return nil
359		}
360	
361		// Compare: is the binary older than what the project requires?
362		needsUpgrade, err := update.NeedsUpgrade(f.Version, projectVersion)
363		if err != nil {
364			return nil // Parse error — don't block
365		}
366		if needsUpgrade {
367			return fmt.Errorf("this project requires DDx v%s or newer (you have %s).\nRun 'ddx upgrade' to update your DDx binary",
368				strings.TrimPrefix(projectVersion, "v"),
369				f.Version)
370		}
371	
372		return nil
373	}
