 86	// TestCheckPackageJSONLocations_StaleNodeModules detects node_modules older than bun.lock.
 87	func TestCheckPackageJSONLocations_StaleNodeModules(t *testing.T) {
 88		workDir := t.TempDir()
 89	
 90		// Create package.json, node_modules, then a newer bun.lock.
 91		if err := os.WriteFile(filepath.Join(workDir, "package.json"), []byte(`{}`), 0o644); err != nil {
 92			t.Fatalf("write package.json: %v", err)
 93		}
 94		if err := os.MkdirAll(filepath.Join(workDir, "node_modules"), 0o755); err != nil {
 95			t.Fatalf("mkdir node_modules: %v", err)
 96		}
 97	
 98		// Write bun.lock after node_modules so it has a newer mtime.
 99		if err := os.WriteFile(filepath.Join(workDir, "bun.lock"), []byte(`lockfileVersion: 0`), 0o644); err != nil {
100			t.Fatalf("write bun.lock: %v", err)
101		}
102		// Backdate node_modules to ensure bun.lock is strictly newer.
103		past := filepath.Join(workDir, "node_modules")
104		info, _ := os.Stat(past)
105		lockInfo, _ := os.Stat(filepath.Join(workDir, "bun.lock"))
106		if !lockInfo.ModTime().After(info.ModTime()) {
107			// Force the difference by touching bun.lock again.
108			now := lockInfo.ModTime().Add(2 * 1e9) // +2s
109			if err := os.Chtimes(filepath.Join(workDir, "bun.lock"), now, now); err != nil {
110				t.Fatalf("chtimes bun.lock: %v", err)
111			}
112		}
113	
114		issues := checkPackageJSONLocations(workDir)
115		if len(issues) != 1 {
116			t.Fatalf("expected 1 issue, got %d: %v", len(issues), issues)
117		}
118		if issues[0].Type != "node_modules_stale" {
119			t.Errorf("expected type node_modules_stale, got %s", issues[0].Type)
120		}
121	}
