631	// resolveAgentSession looks up a session by ID from the agent session log.
632	// Returns nil if the session is not found or cannot be read.
633	func (f *CommandFactory) resolveAgentSession(sessionID string) *agent.SessionEntry {
634		if sessionID == "" {
635			return nil
636		}
637	
638		cfg, err := config.LoadWithWorkingDir(f.WorkingDir)
639		if err != nil {
640			return nil
641		}
642	
643		sessionLogDir := ".ddx/agent-logs"
644		if cfg.Agent != nil && cfg.Agent.SessionLogDir != "" {
645			sessionLogDir = cfg.Agent.SessionLogDir
646		}
647	
648		logDir := agent.ResolveLogDir(f.WorkingDir, sessionLogDir)
649		idx, ok, err := agent.FindSessionIndex(logDir, sessionID)
650		if err != nil {
651			return nil
652		}
653		if ok {
654			entry := agent.SessionIndexEntryToLegacy(idx)
655			bodies := agent.LoadSessionBodies(f.WorkingDir, idx)
656			entry.Prompt = bodies.Prompt
657			entry.Response = bodies.Response
658			entry.Stderr = bodies.Stderr
659			return &entry
660		}
661		return nil
662	}
